INSERT INTO `management_areas` VALUES ('2948c88c-bf92-499f-8f10-b9fb07a4db32','MAP-MKHONDVO','Mkhondvo','Maputo',1,'South Africa / Eswatini','Mkhondvo River subcatchment straddling the RSA–Eswatini border. Left-bank tributary of the Usuthu.'),('3c0bfe34-8889-4e42-b622-e862b757029a','MAP-NGWAVUMA','Ngwavuma','Maputo',1,'South Africa / Eswatini / Mozambique','Ngwavuma River subcatchment. Flows from the RSA highlands through Eswatini into Mozambique, joining the Usuthu before the Maputo confluence.'),('57194fc9-2a7c-487b-809c-948c7abf677c','INC-SABIE','Sabie','Incomati',1,'South Africa / Mozambique','Sabie River subcatchment. Rises near Sabie town in Mpumalanga, flows through the Kruger NP, crosses into Mozambique at Gaza Province and joins the Incomati. Important for ecology in the TFCA.'),('6deed386-1ef1-4f76-89dd-c726c6802c05','MAP-LUSUSHWANA','Lusushwana','Maputo',1,'Eswatini','Lusushwana River subcatchment in western Eswatini. Left-bank tributary of the Usuthu.'),('72f83570-bf5d-4c50-8aa5-7b5a92a2ad77','MAP-USUTHU','Usuthu','Maputo',1,'South Africa / Eswatini / Mozambique','Usuthu (Lusutfu) River mainstem subcatchment. Largest tributary of the Maputo River system, flowing through Eswatini and entering Mozambique before joining the Maputo. GS-16 (Big Bend) is the key IIMA compliance gauge.'),('77b1718d-ab34-402a-abd6-1abcbdd66256','MAP-NGWEMPISI','Ngwempisi','Maputo',1,'South Africa / Eswatini','Ngwempisi River subcatchment in Eswatini. Right-bank tributary of the Usuthu.'),('7dc8c58e-c5c3-4b1b-92e7-4abc7f4177f4','INC-UANETZE','Uanetze','Incomati',1,'Mozambique','Uanetze subcatchment in Mozambique. Left-bank tributary of the lower Incomati.'),('8e7c2875-0733-4f9a-ac37-7a64ca838669','MAP-PONGOLA','Pongola','Maputo',1,'South Africa / Mozambique','Pongola River subcatchment in KwaZulu-Natal (RSA) and Mozambique. Pongolapoort (Jozini) Dam is the primary storage. Joins the Usuthu at Ndumo.'),('97f29b81-1a54-4afa-86f8-4d551ac10894','INC-KOMATI','Komati','Incomati',1,'South Africa / Eswatini / Mozambique','Komati River subcatchment. The main tributary of the Incomati, rising in the Mpumalanga highlands and flowing through Eswatini before re-entering South Africa at Komatipoort, then Mozambique. Maguga and Driekoppies dams are the primary storage infrastructure.'),('9d63856e-37d7-4ebf-bb68-338c9f726546','INC-LOWER','Lower Incomati','Incomati',1,'Mozambique','Lower Incomati mainstem in Mozambique from Ressano Garcia to the Indian Ocean. Includes the Incomati mouth near Xai-Xai. Critical eflow compliance zone (E-23 / X2H036).'),('9feb7b8d-ffca-4673-9da7-6009dc8c9182','INC-MAZIMECHOPES','Mazimechopes','Incomati',1,'Mozambique','Mazimechopes subcatchment in lower Mozambique. Drains into the coastal zone of the Incomati.'),('a95c7ee6-058a-48ba-8825-1394f1cdf3db','INC-CROCODILE','Crocodile','Incomati',1,'South Africa / Mozambique','Crocodile River subcatchment (RSA). Drains the southern slopes of the Mpumalanga escarpment through the Kruger National Park before confluencing with the Incomati at Komatipoort.'),('c34de800-8cbb-4a80-949e-b98ae4582264','INC-MASSINTONTO','Massintonto','Incomati',1,'Mozambique','Massintonto subcatchment in Mozambique. A right-bank tributary joining the lower Incomati.'),('e015e310-dd8d-4cc0-8c02-088fe9c0e51a','MAP-MAPUTO','Lower Maputo','Maputo',1,'Mozambique','Lower Maputo River mainstem in Mozambique. Receives the Usuthu and flows to Maputo Bay. The compliance gauge is E-4 at Salamanga.'),('e0e78a56-e945-47c1-95ff-7f0ba2ea63a3','MAP-MPULUZI','Mpuluzi','Maputo',1,'South Africa / Eswatini','Mpuluzi River subcatchment straddling the RSA–Eswatini border. Tributary of the Usuthu.');
/*!40000 ALTER TABLE `management_areas` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `measurements`
--

DROP TABLE IF EXISTS `measurements`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `measurements` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `station_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `measurement_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parameter_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fsc` double DEFAULT NULL,
  `value` double NOT NULL,
  `unit` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date` timestamp NOT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_by_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_at` timestamp NOT NULL,
  `reviewed_by_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reviewed_at` timestamp NULL DEFAULT NULL,
  `review_notes` text COLLATE utf8mb4_unicode_ci,
  `is_self_override` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `measurements_station_id_foreign` (`station_id`),
  KEY `measurements_parameter_id_foreign` (`parameter_id`),
  KEY `measurements_submitted_by_id_foreign` (`submitted_by_id`),
  KEY `measurements_reviewed_by_id_foreign` (`reviewed_by_id`),
  CONSTRAINT `measurements_parameter_id_foreign` FOREIGN KEY (`parameter_id`) REFERENCES `water_quality_parameters` (`id`),
  CONSTRAINT `measurements_reviewed_by_id_foreign` FOREIGN KEY (`reviewed_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `measurements_station_id_foreign` FOREIGN KEY (`station_id`) REFERENCES `stations` (`id`),
  CONSTRAINT `measurements_submitted_by_id_foreign` FOREIGN KEY (`submitted_by_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

